const Q_CHEMISTRY_2006=[{"id": "objective>Chemistry>2006>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sulphide which is insoluble in dilute hydrochloric acid is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">FeS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ZnS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper sulphide (CuS) is insoluble in dilute hydrochloric acid. This is due to the fact that CuS is a relatively stable compound and does not readily react with dilute hydrochloric acid to form soluble salts.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2006>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, gas X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is oxygen. 2HOCL → 2HCL <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">aq</span>+ O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span>. Note that HOCl is also known as chlorine water.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2006>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On heating, which of the following compounds will decompose to the free metal, nitrogen (IV) oxide and oxygen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ca(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silver nitrate (AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) on heating decomposes to give silver metal, nitrogen dioxide (NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) and oxygen. The reaction is 2AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span> → 2Ag<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2NO2<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>. This is a thermal decomposition reaction where a single compound breaks down into two or more simpler substances under the influence of heat.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2006>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Group IA metals are not found free in nature because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are very reactive and unstable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are malleable and ductile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have high melting and boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduct heat and electricity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Group IA metals are not found free in nature because they are very reactive and unstable. They readily react with oxygen in the air or water in the environment to form compounds, and hence do not exist in their elemental form.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2006>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  In the above diagram, mixture Y is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span> + CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + NaNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the above diagram, Y mixture is a NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span></div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2006>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon exist naturally in the combined state as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">graphite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diamond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wood</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon exist naturally in the combined state as petroleum, wood and natural gas</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2006>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency of a solid catalyst to increase reaction rates depends on its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The efficiency of a solid catalyst to increase reaction rates depends on its surface area. The larger the surface area of the catalyst, the more sites are available for the reactant molecules to collide, leading to an increased rate of reaction. This is the principle behind the use of finely divided catalysts in many industrial processes.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2006>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dynamic equilibrium describes a situation where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a reaction gives back the reactants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the concentration of reactants and products is equal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both forward and reverse reactions proceed at the same rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reactions are converted to products</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dynamic equilibrium in chemistry is a state where the rate of the forward reaction is equal to the rate of the backward reaction. This means that the concentrations of the reactants and products remain constant over time, but not necessarily equal. Therefore, the correct answer is 'both forward and reverse reactions proceed at the same rate'.</div>", "topic": "CHEMICAL EQUILIBRA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>2006>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ion that will give a white precipitate with aqueous NaOH and soluble in excess of the base is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> ions form a white precipitate when reacted with aqueous NaOH, which is soluble in excess of the base. This is due to the formation of the complex ion [Zn(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> in excess NaOH. Therefore, the correct answer is 'Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>'.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2006>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs of substances will react further with oxygen to form a higher oxide. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and NO</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and NO can react further with oxygen to form a higher oxide. SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> can react with oxygen to form SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, and NO can react with oxygen to form NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. Therefore, the correct answer is 'SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and NO'.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2006>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristic colour of the flame shown when a copper salt moistened with concentrated hydrochloric acid on a platinum wire is put on bunsen burner is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lilac</div>", "<div style=\"font-family:Cambria;font-size:17px;\">green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brick red</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a green flame. Flame test on copper gives a bluish green colour.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2006>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the industrial production of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> from natural gas, the CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> produced along with the H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is removed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">washing under pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drying over phosphorous (V) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">passing the mixture into the lime water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">using ammoniacal copper (I) chloride</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the second stage of production, additional hydrogen is generated through the lower-temperature, high pressure and exothermic water gas shift reaction, performed at about 360°C.  <br/>  CO + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>2006>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The raw material used for the smelting of iron ore in a furnace is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The raw material used for the smelting of iron ore in a blast furnace is limestone, which is chemically calcium carbonate (CaCO3). The limestone is used to remove impurities in the iron ore and forms a substance called slag, which is removed from the furnace.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2006>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following typically represents a photochemical reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">formation of water from hydrogen and oxygen molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conversion of dinitrogen (IV) oxide to nitrogen (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decomposition of calcium hydroxide to its oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">conversion of silver halides to grey metallic silver</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A photochemical reaction is a chemical reaction initiated by the absorption of energy in the form of light. The conversion of silver halides to grey metallic silver is a typical example of a photochemical reaction. This is the reaction that occurs in the photographic film when it is exposed to light.</div>", "topic": "RATE OF CHEMICAL REACTION : PHOTO-CHEMICAL REACTIONS"}, {"id": "objective>Chemistry>2006>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas obtained as a product of anaerobic action on organic matter buried in the earth is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen (IV) oxide </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gas obtained as a product of anaerobic action on organic matter buried in the earth is methane. This process is known as anaerobic digestion, where microorganisms break down biodegradable material in the absence of oxygen.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>2006>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbut-2-ene has the structure </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbut-2-ene has the structure of the diagram <img src=\"2006/o4.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2006>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The oxidation of the compound above produces</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-butanone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-butanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-butanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-butanone</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure is a secondary alcohol, oxidation of secondary alcohols yields alkanone </div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2006>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria crude oil is described as light crude because of its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low sulphur content </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high natural gas content </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high octane number </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low aliphatic-hydrocarbon content </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria crude oil is described as light crude because of its low sulphur content. Light crude oil is liquid petroleum that has a low density and flows freely at room temperature. It has a low viscosity, low specific gravity and high API gravity due to the presence of a high proportion of light hydrocarbon fractions.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>2006>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of aliphatic unsaturated hydrocarbon is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pentane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">butanol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">propene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">benzene </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An example of aliphatic unsaturated hydrocarbon is propene. Aliphatic hydrocarbons are organic compounds whose carbon atoms are linked together in chains or rings. They are divided into two groups: saturated hydrocarbons (alkanes) and unsaturated hydrocarbons (alkenes and alkynes). Propene is an alkene, which means it contains a carbon-carbon double bond and is therefore unsaturated.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2006>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following functional groups will give gas bubbles when treated with a saturated solution of sodium hydrogen trioxocarbonate (IV)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">- NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">- OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The functional groups that will give gas bubbles when treated with a saturated solution of sodium hydrogen trioxocarbonate (IV) is <img src=\"2006/o5.png\" style=\"position:relative;max-width:100%;\"/>  <br/>  From Alkanoic Acid.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2006>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has an isomer?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Butane, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> has 2 isomers which include: <br/>  <br/> 1. Butane (the straight chain form)  <br/> 2. 2-methyl propane </div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2006>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - C ≡ CH <br/>  The hybridization in the compound above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and sp</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2006/o7.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hybridization is found in carbon-to-carbon single bonds (C-C) <br/>  <br/> Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> hybridization is found in carbon-to-carbon double bonds (C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-</span>)  <br/>  <br/> Sp hybridization is found in carbon-to-carbon triple bond (≡) <br/>  <br/> The structure above has two types of bonds, \"single and triple\"  <br/> * So we have sp and sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hybridizations. </div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2006>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One mole of a hydrocarbon contains 36g of carbon and its vapour density is 20. The structure of the hydrocarbon is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C≡CH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH=CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>C=CH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vapour Density, V.D = 20 <br/> Recall: V.D × 2 = Relative Molecular Mass <br/> 40 = RMM ----------------- (i) <br/> Note that the question talks about a hydrocarbon, i.e an organic compound which contains carbon and hydrogen only. <br/> 40g = mass of carbon + mass of hydrogen <br/> 40 = 36 + mass of hydrogen <br/> mass of hydrogen = 4.0g <br/> Now, 36g of carbon is 3c = c<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> 4g of hydrogen is 4H = H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/> Therefore, the molecular formula is C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2006>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An emulsion may be produced by shaking a detergent solution with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">palm wine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">palm oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An emulsion is a mixture of two or more liquids that are normally immiscible (unmixable or unblendable). Emulsions are part of a more general class of two-phase systems of matter called colloids. A detergent solution when shaken with palm oil forms an emulsion.</div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>2006>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The product of the combustion of candle wax are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen and water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (II) oxide and water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Candle wax is a hydrocarbon, a compound made from carbon and hydrogen. When you light a candle, the heat of the flame melts the wax near the wick. This liquid wax is drawn up the wick where the heat of the flame vaporizes the liquid wax and starts to break down the hydrocarbons into molecules of hydrogen and carbon. These vaporized molecules are drawn up into the flame, where they react with the oxygen in the air to create heat, light, water vapor (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O), and carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>).</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2006>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a saturated solution of sugar of molar mass 342g at 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C was evaporated to dryness, 34.2g of dry solid was obtained. The solubility of sugar at 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">mass of sugar = 34.2g <br/> molar mass of sugar = 342.0gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />molar mass</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">34.2<hr size=\"1\" />342</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.1</td><td style=\"text-align:center;\">mole</td></tr></table></div> <br/> Volume = 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.05dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">(in</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.1mole<hr size=\"1\" />0.05dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.0</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div> <br/>  <br/>  </div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2006>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following result in the fall of acid rain?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oxides of lead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Particular matter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxides of sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gaseous hydrocarbons</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Acid rain is caused by a chemical reaction that begins when compounds like sulfur dioxide and nitrogen oxides are released into the air. These substances can rise very high into the atmosphere, where they mix and react with water, oxygen, and other chemicals to form more acidic pollutants, known as acid rain.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2006>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water has the ability to dissolve almost all substances because its molecule has a structure with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">one positive end and one neutral end </div>", "<div style=\"font-family:Cambria;font-size:17px;\">one positive and one negative end</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two negative ends</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two positive ends</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water is a polar molecule, meaning it has a positive end and a negative end. This polarity allows it to dissolve many substances by attracting their positive or negative charges.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2006>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a crystal was added to the clear solution of salt, the crystal did not dissolve and the solution remained unchanged. This shows that the solution was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supersaturated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentrated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unsaturated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">saturated </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a crystal is added to a solution and it does not dissolve, it means the solution is already saturated. A saturated solution is one in which no more solute can be dissolved at a given temperature.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2006>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle that contains 11 protons, 12 neutrons and 10 electrons is probably a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutral non-metal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic ion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-metallic ion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral metal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A particle with 11 protons, 12 neutrons, and 10 electrons is an ion because the number of protons does not equal the number of electrons. Since it has more protons than electrons, it is a positive ion, or cation, which is characteristic of metals.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2006>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A difference between chemical and physical change is that in a chemical change</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen is consumed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat is supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reversible process occurs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a new substance is formed </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The key difference between a chemical change and a physical change is that a chemical change involves a change in the substance's composition, resulting in the formation of a new substance. Physical changes, on the other hand, do not alter the substance's identity.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2006>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of 2.5 moles of oxygen at s.t.p is  <br/>  [molar volume of gas at s.t.p. = 22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">84.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">28.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">56.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1 mole of any gas occupies 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p  <br/>  <br/> 2.5 mole of oxygen gas will occupy x dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  <br/> 1/2.5 = 22.4/x = 22.4/x; x = 2.5 x 22.4  <br/>  <br/>  = 56.0dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2006>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear fission involves the splitting of energy and radiation in two nuclei of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nearly equal masses with a release of energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal masses with a release of energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal masses with a release of energy and radiation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unequal masses without any release of energy. </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear fission is a reaction in which a heavy nucleus splits spontaneously or on impact with another particle, with the release of energy. The splitting results in two nuclei of nearly equal masses.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2006>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the molar mass of a substance, 0.4 mole of the substance has a mass of 25.0g?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">62.5g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40.0g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.3g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The molar mass of a substance is the mass of one mole of that substance. It can be calculated by dividing the mass of the substance by the number of moles. In this case, 25.0g divided by 0.4 mole equals 62.5g. <br/> No of mole = Mass/Molar mass <br/> 0.4=25/Molar mass <br/> Molar mass= 25/0.4=62.5g</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2006>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The element with the electron configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> corresponds to the element nitrogen. The electron configuration describes the distribution of electrons in an atom. It is based on the principle that energy levels of an atom are filled in order of increasing energy.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2006>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in atomic size and an increase in nuclear charge across a period leads to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the tendency to lose electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in chemical reactivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in electropositivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in covalency in bond formation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As you move across a period from left to right, the atomic size decreases and the nuclear charge increases. This leads to a decrease in electropositivity, which is the tendency of an atom to lose electrons and form positive ions.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2006>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The order in which a mixture of sand, ammonium chloride and sodium chloride can be separated is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dissolution → dryness → filtration → evaporation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration → sublimation → evaporation → dryness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation → dissolution → filtration → evaporation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolution → filtration → sublimation → evaporation </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mixture can be separated by first sublimating the ammonium chloride, then dissolving the remaining mixture in water, followed by filtration to remove the sand, and finally evaporating the water to obtain the sodium chloride.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2006>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The idea of planetary electrons was that of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rutherford</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thompson</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bohr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dalton</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rutherford posited that at the center of an atom, say a Sodium atom is the nucleus consisting of 11 protons and 11 neutrons with 11 electrons orbiting this nucleus. Rutherford's new model for the atom, based on the experimental results, contained the new features of a relatively high central charge concentrated into a very small volume in comparison to the rest of the atom and with this central volume also containing the bulk of the atomic mass of the atom. <br/> The electrons rotate round the nucleus, in the same way that the planets rotate round the sun.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2006>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas at 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is warmed to 80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C at a fixed pressure, the fractional increase in volume is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.009</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.093</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.910</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.090</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/>  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = x, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 323k; T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 353k  <br/>  <br/>  Using Charle's law; V ∝ T; V = KT; V/T = K  <br/>  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>; V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>; V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 30 x 353/323 = 32.8cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/>  Fractional increase in volume: V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 32.8-30/30 = 2.8/30 = 0.093</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2006>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 5O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 4CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> In the reaction above, The mass of carbon (IV) oxide produced on a burning 78g of ethyne is ...  <br/>  [C = 12, O = 16, H = 1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">264g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">39g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">352g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">156g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 50<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 4CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/>  <br/> From the equation above; <br/>  <br/> 2(24+2)g of the ethyne produces 4(44)g of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/> 52g of ethyne produce 176g of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  <br/> 78g of ethyne will produce xg of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/> 52/78 = 178/x <br/>  <br/> 52x = 176 x 78  <br/>  <br/>  x = 176 x 78/52 = 176 x 3/2 = 264g </div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2006>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ion that can be used as oxidizing agent is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Au<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> (Fluoride ion) has the highest oxidizing ability, F<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> > Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> > Br<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2006>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trioxonitrate (V) acid is not used for preparing hydrogen gas from metals because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is strongly oxidizing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is volatile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">renders the metal passive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">form a layer of oxide on the metal. </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trioxonitrate (V) acid, also known as nitric acid, is a strong oxidizing agent. This means it has the ability to gain electrons and cause other substances to lose electrons (be oxidized). Therefore, it is not used for preparing hydrogen gas from metals because it would oxidize the hydrogen gas, preventing its formation.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2006>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2HBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/>  The reaction above is carried out at 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. If ∆S is -106 J mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the reaction will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">not proceed spontaneously at the given temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proceed spontaneously at the given temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">proceed in the reverse direction at the given temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proceed spontaneously at lower temperature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall that, <br/>  <br/>  ∆G = ∆H - T∆S <br/>  <br/> If ∆G = -ve, then the reaction is spontanuous  <br/>  <br/> ∆H = -72KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  <br/> ∆S = -106Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = -0.106KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  <br/> T = 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 298k  <br/>  <br/> ∆G = -72 - - 0.106 x 298 <br/>  <br/> ∆G = -72 + 31.6  <br/>  <br/> ∆G = -40.4KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  <br/>  Hence, the reaction will process spontaneously at 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C because ∆G is negative. </div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>2006>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zinc and carbon rods are used as anode and cathode respectively in a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Leclanche cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead accumulator </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Daniel cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voltaic cell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They are used in a Lenclanche Cell. It is a primary electrochemical cell having a zinc cathode in contact with zinc chloride, ammonium chloride (as a solution or a paste) as the electrolyte, and a carbon anode in contact with a mixture of manganese dioxide and carbon powder.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2006>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solution that will conduct the highest amount of electricity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of hydrochloric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of hydrochloric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of ethanoic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of ethanoic acid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solution that will conduct the highest amount of electricity is 2.0 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of hydrochloric acid. The conductivity of a solution is directly proportional to the concentration of its ions. Hydrochloric acid is a strong acid that completely ionizes in solution, producing a high concentration of ions. Therefore, a higher concentration of hydrochloric acid will result in a higher conductivity.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2006>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following is the oxidation number of sulphur equal to -2?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">S8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S, the oxidation number of sulphur is -2. The oxidation number is a concept in chemistry that helps in balancing redox reactions. It represents the charge that an atom would have if all the bonding electrons were transferred to the atom with a higher electronegativity. In H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S, each hydrogen atom has an oxidation number of +1, and since the compound is neutral, the sulphur atom must have an oxidation number of -2 to balance the +2 from the two hydrogen atoms.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2006>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolysis of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> using platinum electrodes, the reaction at the anode is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> - 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> - 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 2OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2OH- + 2OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolysis of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> using platinum electrodes, the reaction at the anode is 4OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> - 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. The anode is the electrode where oxidation occurs in an electrochemical cell. In this case, hydroxide ions (OH^-) are oxidized to form water and oxygen gas, with the release of electrons.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2006>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span> + 2HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2NaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H2O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/> How many moles of sodium trioxocarbonate (IV) are there in a 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> solution which required 10cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.05 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> hydrochloric  acid solution to neutralize it?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.000 mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.100 mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.00025 mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.111 mole</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/ C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> =n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> <br/> 0.05 x 10/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> x 25 = 2/1 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 0.05 x 10/50 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 0.01 mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/> no of mole = conc. x vol/1000 <br/> =0.01 x 25/1000 <br/> =0.25/1000 <br/> =0.00025 mole</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2006>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the heat of combustion of hydrogen is -285.8kJ, what is the heat of formation of water?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+571.6kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-571.6kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-285.8kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+285.8kJ</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> The heat of the reaction is the heat of formation of water which is still the same as the heat of combustion of hydrogen; hence <br/> ∆H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">θ</span> combustion of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ∆H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">θ</span> formation of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2006>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">5SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(j)</span> → K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + 2MnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>(aq) + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span>  <br/> In the reaction above, the products give a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">purple solution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">purple precipitate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">colourless precipitate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colourless solution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will give a colourless solution. On a warm acidified KMno<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> with the reactant , the purple colour will be decolourized this is because MnO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>which is purple in colour has be reduced to Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> which is colourless.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}];
